887: func (a *Server) CheckU2FSignResponse(ctx context.Context, user string, response *u2f.AuthenticateChallengeResponse) error {
888: 	// before trying to register a user, see U2F is actually setup on the backend
889: 	cap, err := a.GetAuthPreference()
890: 	if err != nil {
891: 		return trace.Wrap(err)
892: 	}
893: 	_, err = cap.GetU2F()
894: 	if err != nil {
895: 		return trace.Wrap(err)
896: 	}
897: 
898: 	return a.checkU2F(ctx, user, *response, a.Identity)
899: }
