{"content":"490: // SSHAgentU2FLogin requests a U2F sign request (authentication challenge) via
491: // the proxy. If the credentials are valid, the proxy wiil return a challenge.
492: // We then perform the signing and pass the signature to the proxy. If the
493: // authentication succeeds, we will get a temporary certificate back.
494: func SSHAgentU2FLogin(ctx context.Context, login SSHLoginU2F) (*auth.SSHLoginResponse, error) {
495: 	clt, _, err := initClient(login.ProxyAddr, login.Insecure, login.Pool)
496: 	if err != nil {
497: 		return nil, trace.Wrap(err)
498: 	}
499: 
500: 	challengeRaw, err := clt.PostJSON(ctx, clt.Endpoint("webapi", "u2f", "signrequest"), U2fSignRequestReq{
501: 		User: login.User,
502: 		Pass: login.Password,
503: 	})
504: 	if err != nil {
505: 		return nil, trace.Wrap(err)
506: 	}
507: 
508: 	var res auth.U2FAuthenticateChallenge
509: 	if err := json.Unmarshal(challengeRaw.Bytes(), &res); err != nil {
510: 		return nil, trace.Wrap(err)
511: 	}
512: 	if len(res.Challenges) == 0 {
513: 		// Challenge sent by a pre-6.0 auth server, fall back to the old
514: 		// single-device format.
515: 		if res.AuthenticateChallenge == nil {
516: 			// This shouldn't happen with a well-behaved auth server, but check
517: 			// anyway.
518: 			return nil, trace.BadParameter("server sent no U2F challenges")
519: 		}
520: 		res.Challenges = []u2f.AuthenticateChallenge{*res.AuthenticateChallenge}
521: 	}
522: 
523: 	fmt.Println("Please press the button on your U2F key")
524: 	facet := "https://" + strings.ToLower(login.ProxyAddr)
525: 	challengeResp, err := u2f.AuthenticateSignChallenge(ctx, facet, res.Challenges...)
526: 	if err != nil {
527: 		return nil, trace.Wrap(err)
528: 	}
529: 
530: 	re, err := clt.PostJSON(ctx, clt.Endpoint("webapi", "u2f", "certs"), CreateSSHCertWithU2FReq{
531: 		User:              login.User,
532: 		U2FSignResponse:   *challengeResp,
533: 		PubKey:            login.PubKey,
534: 		TTL:               login.TTL,
535: 		Compatibility:     login.Compatibility,
536: 		RouteToCluster:    login.RouteToCluster,
537: 		KubernetesCluster: login.KubernetesCluster,
538: 	})
539: 	if err != nil {
540: 		return nil, trace.Wrap(err)
541: 	}
542: 
543: 	var out *auth.SSHLoginResponse
544: 	err = json.Unmarshal(re.Bytes(), &out)
545: 	if err != nil {
546: 		return nil, trace.Wrap(err)
547: 	}
548: 
549: 	return out, nil
550: }
