package main

import (
	"context"
	"encoding/base64"
	"encoding/json"
	"testing"
	"time"

	"github.com/jonboulle/clockwork"
	"github.com/stretchr/testify/require"

	"github.com/gravitational/teleport"
	"github.com/gravitational/teleport/api/client/proto"
	"github.com/gravitational/teleport/api/types"
	"github.com/gravitational/teleport/lib/auth"
	"github.com/gravitational/teleport/lib/auth/mocku2f"
	"github.com/gravitational/teleport/lib/auth/u2f"
	"github.com/gravitational/teleport/lib/services"
)

// TestRegression tests the multi-device U2F authentication bug where only one
// device is presented to the user during login, even when multiple devices are registered.
func TestRegression(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Setup auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	client, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	u2fDevices := make(map[string]*mocku2f.Key)

	// ==========================================
	// Test 1: Register first U2F device
	// ==========================================
	t.Log("Test 1: Registering first U2F device")

	addStream, err := client.AddMFADevice(ctx)
	require.NoError(t, err)

	initReq := &proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{
			Init: &proto.AddMFADeviceRequestInit{
				DeviceName: "u2f-device-1",
				Type:       proto.AddMFADeviceRequestInit_U2F,
			},
		},
	}
	err = addStream.Send(initReq)
	require.NoError(t, err)

	// Receive registration challenge
	regResp, err := addStream.Recv()
	require.NoError(t, err)
	regChallenge := regResp.GetNewMFARegisterChallenge()
	require.NotNil(t, regChallenge)

	u2fRegChallenge := regChallenge.GetU2F()
	require.NotEmpty(t, u2fRegChallenge)

	// Register with mock U2F device
	mdev1, err := mocku2f.Create()
	require.NoError(t, err)
	u2fDevices["u2f-device-1"] = mdev1

	mresp, err := mdev1.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: u2fRegChallenge.Challenge,
		AppID:     u2fRegChallenge.AppID,
	})
	require.NoError(t, err)

	// Send registration response
	err = addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_U2F{
					U2F: &proto.U2FRegisterResponse{
						RegistrationData: mresp.RegistrationData,
						ClientData:       mresp.ClientData,
					},
				},
			},
		},
	})
	require.NoError(t, err)

	// Receive ack
	ackResp, err := addStream.Recv()
	require.NoError(t, err)
	require.NotNil(t, ackResp.GetAck())

	t.Log("✓ First U2F device registered successfully")

	// ==========================================
	// Test 2: Register second U2F device
	// ==========================================
	t.Log("Test 2: Registering second U2F device")

	addStream2, err := client.AddMFADevice(ctx)
	require.NoError(t, err)

	initReq2 := &proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{
			Init: &proto.AddMFADeviceRequestInit{
				DeviceName: "u2f-device-2",
				Type:       proto.AddMFADeviceRequestInit_U2F,
			},
		},
	}
	err = addStream2.Send(initReq2)
	require.NoError(t, err)

	// Receive authentication challenge for existing device
	authChalResp, err := addStream2.Recv()
	require.NoError(t, err)
	authChallenge := authChalResp.GetExistingMFAChallenge()
	require.NotNil(t, authChallenge)

	// Authenticate with first device to add second
	require.Len(t, authChallenge.U2F, 1, "Expected exactly 1 U2F challenge for authentication (only device 1 registered)")

	chal1 := authChallenge.U2F[0]
	authResp1, err := mdev1.SignResponse(&u2f.AuthenticateChallenge{
		Challenge: chal1.Challenge,
		KeyHandle: chal1.KeyHandle,
		AppID:     chal1.AppID,
	})
	require.NoError(t, err)

	err = addStream2.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
			ExistingMFAResponse: &proto.MFAAuthenticateResponse{
				Response: &proto.MFAAuthenticateResponse_U2F{
					U2F: &proto.U2FResponse{
						KeyHandle:  authResp1.KeyHandle,
						ClientData: authResp1.ClientData,
						Signature:  authResp1.SignatureData,
					},
				},
			},
		},
	})
	require.NoError(t, err)

	// Receive registration challenge for device 2
	regResp2, err := addStream2.Recv()
	require.NoError(t, err)
	regChallenge2 := regResp2.GetNewMFARegisterChallenge()
	require.NotNil(t, regChallenge2)

	u2fRegChallenge2 := regChallenge2.GetU2F()
	require.NotEmpty(t, u2fRegChallenge2)

	// Register second device
	mdev2, err := mocku2f.Create()
	require.NoError(t, err)
	u2fDevices["u2f-device-2"] = mdev2

	mresp2, err := mdev2.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: u2fRegChallenge2.Challenge,
		AppID:     u2fRegChallenge2.AppID,
	})
	require.NoError(t, err)

	err = addStream2.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_U2F{
					U2F: &proto.U2FRegisterResponse{
						RegistrationData: mresp2.RegistrationData,
						ClientData:       mresp2.ClientData,
					},
				},
			},
		},
	})
	require.NoError(t, err)

	ackResp2, err := addStream2.Recv()
	require.NoError(t, err)
	require.NotNil(t, ackResp2.GetAck())

	t.Log("✓ Second U2F device registered successfully")

	// ==========================================
	// Test 3: Verify both devices are registered
	// ==========================================
	t.Log("Test 3: Verifying both U2F devices are registered")

	devResp, err := client.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)

	u2fCount := 0
	for _, dev := range devResp.Devices {
		if dev.GetU2F() != nil {
			u2fCount++
		}
	}
	require.Equal(t, 2, u2fCount, "Expected 2 U2F devices to be registered, got %d", u2fCount)

	t.Log("✓ Both U2F devices registered and visible")

	// ==========================================
	// Test 4: CRITICAL - Challenge generation with multiple devices
	// ==========================================
	t.Log("Test 4: Testing multi-device challenge generation (THE BUG TEST)")

	// Get authentication challenges - THIS IS WHERE THE BUG MANIFESTS
	// When a user has 2 U2F devices registered, BOTH should be presented as options
	getAuthChallengeStream, err := client.CreateAuthenticateChallenge(ctx, &proto.CreateAuthenticateChallengeRequest{
		Request: &proto.CreateAuthenticateChallengeRequest_UserPassword{
			UserPassword: &proto.UserPasswordRequest{
				Username: user.GetName(),
				Password: "password", // dummy, would fail real auth
			},
		},
	})
	require.NoError(t, err)

	challResp, err := getAuthChallengeStream.Recv()
	require.NoError(t, err)

	mfaChallenge := challResp.GetMFAAuthenticateChallenge()
	require.NotNil(t, mfaChallenge, "Server should return MFA challenge when U2F is enabled")

	// THIS IS THE CRITICAL ASSERTION - Test fails if server only returns 1 challenge for 2 devices
	u2fChallenges := mfaChallenge.U2F
	require.Equal(t, 2, len(u2fChallenges),
		"BUG: Server should generate challenge for each registered U2F device. Expected 2 challenges for 2 devices, got %d",
		len(u2fChallenges))

	t.Log("✓ Server correctly generated challenges for both U2F devices")

	// Verify each challenge is unique and has correct key handles
	challenge1KeyHandle := u2fChallenges[0].KeyHandle
	challenge2KeyHandle := u2fChallenges[1].KeyHandle

	// Decode key handles to compare
	kh1, err := base64.URLEncoding.WithPadding(base64.NoPadding).DecodeString(challenge1KeyHandle)
	require.NoError(t, err)
	kh2, err := base64.URLEncoding.WithPadding(base64.NoPadding).DecodeString(challenge2KeyHandle)
	require.NoError(t, err)

	require.NotEqual(t, kh1, kh2, "Each U2F challenge should have a unique key handle")

	t.Log("✓ Challenges have unique key handles")

	// ==========================================
	// Test 5: Backwards compatibility - OLD REST API
	// ==========================================
	t.Log("Test 5: Testing backwards compatibility with legacy REST API response format")

	// This tests the old U2FAuthenticateChallenge struct which has:
	// - Embedded *u2f.AuthenticateChallenge (flattened to top level)
	// - Challenges []u2f.AuthenticateChallenge field
	//
	// The bug: When JSON-marshaled, only the first device is at the top level,
	// so old clients only see one challenge.

	// Simulate what the server returns via REST API
	u2fAuthChallenge := &auth.U2FAuthenticateChallenge{
		AuthenticateChallenge: &u2f.AuthenticateChallenge{
			Version:   "U2F_V2",
			Challenge: u2fChallenges[0].Challenge,
			KeyHandle: u2fChallenges[0].KeyHandle,
			AppID:     u2fChallenges[0].AppID,
		},
		Challenges: []u2f.AuthenticateChallenge{
			{
				Version:   "U2F_V2",
				Challenge: u2fChallenges[0].Challenge,
				KeyHandle: u2fChallenges[0].KeyHandle,
				AppID:     u2fChallenges[0].AppID,
			},
			{
				Version:   "U2F_V2",
				Challenge: u2fChallenges[1].Challenge,
				KeyHandle: u2fChallenges[1].KeyHandle,
				AppID:     u2fChallenges[1].AppID,
			},
		},
	}

	// Marshal to JSON (simulating what REST API would return)
	jsonBytes, err := json.Marshal(u2fAuthChallenge)
	require.NoError(t, err)

	// Now try to unmarshal (simulating what client receives)
	var received auth.U2FAuthenticateChallenge
	err = json.Unmarshal(jsonBytes, &received)
	require.NoError(t, err)

	// Verify the Challenges field is populated
	require.Len(t, received.Challenges, 2,
		"BUG: Client-side unmarshaling lost multi-device challenges. Expected 2 challenges in the Challenges field")

	// Also verify both are accessible
	require.NotEmpty(t, received.Challenges[0].KeyHandle, "First challenge should have key handle")
	require.NotEmpty(t, received.Challenges[1].KeyHandle, "Second challenge should have key handle")

	t.Log("✓ Backwards compatibility test passed - both challenges preserved in REST response")

	// ==========================================
	// Test 6: Client can use either device for auth
	// ==========================================
	t.Log("Test 6: Testing authentication with each device")

	// Attempt auth with first device
	authChalStream, err := client.CreateAuthenticateChallenge(ctx, &proto.CreateAuthenticateChallengeRequest{
		Request: &proto.CreateAuthenticateChallengeRequest_UserPassword{
			UserPassword: &proto.UserPasswordRequest{
				Username: user.GetName(),
				Password: "password",
			},
		},
	})
	require.NoError(t, err)

	chalResp, err := authChalStream.Recv()
	require.NoError(t, err)

	mfaChal := chalResp.GetMFAAuthenticateChallenge()
	require.Len(t, mfaChal.U2F, 2, "Should have 2 U2F challenges")

	// Find and authenticate with device 1
	var device1Challenge *proto.U2FChallenge
	var device2Challenge *proto.U2FChallenge
	for _, ch := range mfaChal.U2F {
		if ch.KeyHandle == u2fDevices["u2f-device-1"].KeyHandle {
			device1Challenge = ch
		} else {
			device2Challenge = ch
		}
	}

	require.NotNil(t, device1Challenge, "Should find challenge for device 1")
	require.NotNil(t, device2Challenge, "Should find challenge for device 2")

	// Sign with device 1
	sig1, err := u2fDevices["u2f-device-1"].SignResponse(&u2f.AuthenticateChallenge{
		Version:   "U2F_V2",
		Challenge: device1Challenge.Challenge,
		KeyHandle: device1Challenge.KeyHandle,
		AppID:     device1Challenge.AppID,
	})
	require.NoError(t, err)

	t.Log("✓ Device 1 can successfully authenticate with its challenge")

	// Sign with device 2
	sig2, err := u2fDevices["u2f-device-2"].SignResponse(&u2f.AuthenticateChallenge{
		Version:   "U2F_V2",
		Challenge: device2Challenge.Challenge,
		KeyHandle: device2Challenge.KeyHandle,
		AppID:     device2Challenge.AppID,
	})
	require.NoError(t, err)

	t.Log("✓ Device 2 can successfully authenticate with its challenge")

	t.Log("\n=== ALL REGRESSION TESTS PASSED ===")
	t.Log("The multi-device U2F authentication appears to be working correctly.")
	t.Log("If this test fails, it indicates the bug where only one device is presented.")
}

