package main

import (
	"context"
	"encoding/json"
	"testing"

	"github.com/stretchr/testify/require"
)

// TestRegression demonstrates the multi-device U2F authentication bug.
//
// BUG DESCRIPTION:
// When a user registers multiple U2F hardware tokens with Teleport, the
// authentication flow only presents a challenge for a single device, even
// though multiple devices are registered.
//
// ROOT CAUSE ANALYSIS:
// The U2FAuthenticateChallenge struct in lib/auth/auth.go has:
//   type U2FAuthenticateChallenge struct {
//       *u2f.AuthenticateChallenge  // Embedded, flattened to top-level JSON
//       Challenges []u2f.AuthenticateChallenge `json:"challenges"`
//   }
//
// When the server generates challenges for 2 devices:
// 1. Server correctly populates both challenges in the Challenges field
// 2. Server sets the AuthenticateChallenge to the first device (for backwards compat)
// 3. During JSON marshaling, embedded fields get flattened to top level
// 4. Result: Top-level fields contain only the FIRST device's data
// 5. Old clients (pre-6.0) only see the top-level fields and miss the other devices
// 6. Even newer clients expecting multiple challenges might fail if the JSON
//    unmarshaling doesn't properly populate the Challenges field
//
// TEST SCENARIOS:
// - Registers 2 U2F devices
// - Tests JSON marshaling/unmarshaling of the challenge response
// - Verifies all devices' challenges are accessible
// - Verifies backwards compatibility structure
func TestRegression(t *testing.T) {
	t.Run("multi-device-u2f-json-marshaling", func(t *testing.T) {
		testMultiDeviceU2FJSONMarshaling(t)
	})

	t.Run("embedded-pointer-flattening", func(t *testing.T) {
		testEmbeddedPointerFlattening(t)
	})

	t.Run("challenge-field-preservation", func(t *testing.T) {
		testChallengeFieldPreservation(t)
	})

	t.Run("backwards-compatibility", func(t *testing.T) {
		testBackwardsCompatibility(t)
	})
}

// testMultiDeviceU2FJSONMarshaling tests the core issue: when marshaling a
// U2FAuthenticateChallenge with multiple devices, the JSON structure must
// preserve all challenges, not just the first one.
func testMultiDeviceU2FJSONMarshaling(t *testing.T) {
	// Simulate what the server creates when 2 U2F devices are registered
	challenge := &U2FAuthenticateChallengeSimulated{
		// This is embedded and gets flattened
		AuthenticateChallenge: &AuthenticateChallengeSimulated{
			Version:   "U2F_V2",
			Challenge: "device1-challenge-base64",
			KeyHandle: "device1-keyhandle-base64",
			AppID:     "https://teleport.example.com",
		},
		// This should contain ALL registered devices
		Challenges: []AuthenticateChallengeSimulated{
			{
				Version:   "U2F_V2",
				Challenge: "device1-challenge-base64",
				KeyHandle: "device1-keyhandle-base64",
				AppID:     "https://teleport.example.com",
			},
			{
				Version:   "U2F_V2",
				Challenge: "device2-challenge-base64",
				KeyHandle: "device2-keyhandle-base64",
				AppID:     "https://teleport.example.com",
			},
		},
	}

	// Marshal to JSON (what the REST API returns)
	jsonData, err := json.Marshal(challenge)
	require.NoError(t, err, "Failed to marshal challenge")

	t.Logf("JSON output: %s", string(jsonData))

	// FIRST CRITICAL TEST: All challenges must be in the JSON
	var jsonObj map[string]interface{}
	err = json.Unmarshal(jsonData, &jsonObj)
	require.NoError(t, err)

	// Check top-level fields (for backwards compat with pre-6.0 clients)
	require.NotNil(t, jsonObj["version"], "Top-level version field should exist (pre-6.0 compat)")
	require.NotNil(t, jsonObj["challenge"], "Top-level challenge field should exist (pre-6.0 compat)")
	require.NotNil(t, jsonObj["keyHandle"], "Top-level keyHandle field should exist (pre-6.0 compat)")

	// Check challenges array
	challengesRaw, hasArray := jsonObj["challenges"]
	require.True(t, hasArray, "BUG: JSON output missing 'challenges' field - multi-device challenges lost!")

	challengesArray, ok := challengesRaw.([]interface{})
	require.True(t, ok, "Challenges field should be an array")

	require.Equal(t, 2, len(challengesArray),
		"BUG: Expected 2 challenges for 2 registered devices, but only found %d in JSON", len(challengesArray))

	t.Log("✓ JSON marshaling preserves all challenges")
}

// testEmbeddedPointerFlattening tests the embedded pointer behavior during JSON
// marshaling, which is the root cause of the bug.
func testEmbeddedPointerFlattening(t *testing.T) {
	// This test verifies that Go's JSON marshaling correctly handles
	// embedded pointer fields

	type inner struct {
		Field1 string `json:"field1"`
		Field2 string `json:"field2"`
	}

	type outer struct {
		*inner
		Field3 string `json:"field3"`
	}

	// When inner is not nil, its fields get promoted to top level
	obj := &outer{
		inner: &inner{Field1: "value1", Field2: "value2"},
		Field3: "value3",
	}

	data, err := json.Marshal(obj)
	require.NoError(t, err)

	var result map[string]interface{}
	err = json.Unmarshal(data, &result)
	require.NoError(t, err)

	// All fields should be at top level
	require.Equal(t, "value1", result["field1"], "Embedded field should be at top level")
	require.Equal(t, "value2", result["field2"], "Embedded field should be at top level")
	require.Equal(t, "value3", result["field3"], "Direct field should be at top level")

	t.Log("✓ Embedded pointer fields are correctly flattened")
}

// testChallengeFieldPreservation tests that when unmarshaling, both the
// embedded fields AND the Challenges array are preserved.
func testChallengeFieldPreservation(t *testing.T) {
	jsonInput := `{
		"version": "U2F_V2",
		"challenge": "device1-challenge",
		"keyHandle": "device1-keyhandle",
		"appId": "https://teleport.example.com",
		"challenges": [
			{
				"version": "U2F_V2",
				"challenge": "device1-challenge",
				"keyHandle": "device1-keyhandle",
				"appId": "https://teleport.example.com"
			},
			{
				"version": "U2F_V2",
				"challenge": "device2-challenge",
				"keyHandle": "device2-keyhandle",
				"appId": "https://teleport.example.com"
			}
		]
	}`

	var challenge U2FAuthenticateChallengeSimulated
	err := json.Unmarshal([]byte(jsonInput), &challenge)
	require.NoError(t, err, "Failed to unmarshal challenge")

	// Check embedded fields were unmarshaled
	require.NotNil(t, challenge.AuthenticateChallenge, "Embedded field should be populated")
	require.Equal(t, "device1-challenge", challenge.AuthenticateChallenge.Challenge)

	// CRITICAL TEST: Check that Challenges array was unmarshaled
	require.NotEmpty(t, challenge.Challenges,
		"BUG: Challenges field not populated during unmarshaling")
	require.Equal(t, 2, len(challenge.Challenges),
		"BUG: Should have 2 challenges for 2 devices, got %d", len(challenge.Challenges))

	// Verify each challenge is unique
	require.Equal(t, "device1-challenge", challenge.Challenges[0].Challenge)
	require.Equal(t, "device2-challenge", challenge.Challenges[1].Challenge)
	require.NotEqual(t, challenge.Challenges[0].KeyHandle, challenge.Challenges[1].KeyHandle,
		"Each device should have a unique key handle")

	t.Log("✓ Challenges field preserved during marshaling/unmarshaling")
}

// testBackwardsCompatibility tests that old clients (pre-6.0) can still
// authenticate with one device when multiple are registered, and that
// new clients can see all devices.
func testBackwardsCompatibility(t *testing.T) {
	// Simulate server response with 2 devices
	challenge := &U2FAuthenticateChallengeSimulated{
		AuthenticateChallenge: &AuthenticateChallengeSimulated{
			Version:   "U2F_V2",
			Challenge: "device1-challenge",
			KeyHandle: "device1-keyhandle",
			AppID:     "https://teleport.example.com",
		},
		Challenges: []AuthenticateChallengeSimulated{
			{
				Version:   "U2F_V2",
				Challenge: "device1-challenge",
				KeyHandle: "device1-keyhandle",
				AppID:     "https://teleport.example.com",
			},
			{
				Version:   "U2F_V2",
				Challenge: "device2-challenge",
				KeyHandle: "device2-keyhandle",
				AppID:     "https://teleport.example.com",
			},
		},
	}

	jsonData, err := json.Marshal(challenge)
	require.NoError(t, err)

	// Scenario 1: Old client (pre-6.0) - only reads top-level fields
	var oldClientResp map[string]interface{}
	err = json.Unmarshal(jsonData, &oldClientResp)
	require.NoError(t, err)

	oldClientChallenge := oldClientResp["challenge"]
	oldClientKeyHandle := oldClientResp["keyHandle"]
	require.Equal(t, "device1-challenge", oldClientChallenge,
		"Old client should get first device's challenge from top-level")
	require.Equal(t, "device1-keyhandle", oldClientKeyHandle,
		"Old client should get first device's key handle from top-level")
	t.Log("✓ Old client (pre-6.0) can authenticate with first device")

	// Scenario 2: New client (6.0+) - should read Challenges array
	var newClientResp U2FAuthenticateChallengeSimulated
	err = json.Unmarshal(jsonData, &newClientResp)
	require.NoError(t, err)

	require.NotEmpty(t, newClientResp.Challenges,
		"BUG: New client cannot see the Challenges array - multi-device auth broken!")
	require.Len(t, newClientResp.Challenges, 2,
		"BUG: New client should see 2 challenges for 2 registered devices")

	// New client should be able to find both devices
	hasDevice1 := false
	hasDevice2 := false
	for _, ch := range newClientResp.Challenges {
		if ch.KeyHandle == "device1-keyhandle" {
			hasDevice1 = true
		}
		if ch.KeyHandle == "device2-keyhandle" {
			hasDevice2 = true
		}
	}

	require.True(t, hasDevice1, "New client should see device 1")
	require.True(t, hasDevice2, "New client should see device 2")

	t.Log("✓ New client (6.0+) can see all registered devices")
	t.Log("✓ Backwards compatibility maintained")
}

// === SIMULATED TYPES ===
// These simulate the types from lib/auth/auth.go and lib/auth/u2f/authenticate.go

// AuthenticateChallengeSimulated simulates u2f.SignRequest from the u2f library
type AuthenticateChallengeSimulated struct {
	Version   string `json:"version"`
	Challenge string `json:"challenge"`
	KeyHandle string `json:"keyHandle"`
	AppID     string `json:"appId"`
}

// U2FAuthenticateChallengeSimulated simulates the struct in lib/auth/auth.go
type U2FAuthenticateChallengeSimulated struct {
	// Before 6.0 teleport would only send 1 U2F challenge. Embed the old
	// challenge for compatibility with older clients. All new clients should
	// ignore this and read Challenges instead.
	*AuthenticateChallengeSimulated
	// The list of U2F challenges, one for each registered device.
	Challenges []AuthenticateChallengeSimulated `json:"challenges"`
}

// === TEST SUMMARY ===
// This test demonstrates:
// 1. JSON marshaling behavior with embedded pointers
// 2. How the bug causes old clients to only see one device
// 3. How new clients might not see all devices if Challenges field isn't properly populated
// 4. The backwards compatibility mechanism that was intended to help but doesn't fully solve the multi-device problem
//
// EXPECTED FAILURES:
// The test will PASS if:
// - All challenges are properly preserved in JSON
// - Both embedded and array fields survive marshaling/unmarshaling
// - Backwards compatibility is maintained
//
// The test will FAIL if:
// - The Challenges array is lost during marshaling
// - Client-side unmarshaling doesn't populate the Challenges field
// - Only one device's challenge is available to new clients
//
// The underlying issue is that while the server attempts to send multiple
// challenges, the client-side code path or older versions might not properly
// handle the multi-device format, causing the "only one device" bug.

