// testMultiDeviceU2FJSONMarshaling tests the core issue: when marshaling a
// U2FAuthenticateChallenge with multiple devices, the JSON structure must
// preserve all challenges, not just the first one.
func testMultiDeviceU2FJSONMarshaling(t *testing.T) {
	// Simulate what the server creates when 2 U2F devices are registered
	challenge := &U2FAuthenticateChallengeSimulated{
		// This is embedded and gets flattened
		AuthenticateChallenge: &AuthenticateChallengeSimulated{
			Version:   "U2F_V2",
			Challenge: "device1-challenge-base64",
			KeyHandle: "device1-keyhandle-base64",
			AppID:     "https://teleport.example.com",
		},
		// This should contain ALL registered devices
		Challenges: []AuthenticateChallengeSimulated{
			{
				Version:   "U2F_V2",
				Challenge: "device1-challenge-base64",
				KeyHandle: "device1-keyhandle-base64",
				AppID:     "https://teleport.example.com",
			},
			{
				Version:   "U2F_V2",
				Challenge: "device2-challenge-base64",
				KeyHandle: "device2-keyhandle-base64",
				AppID:     "https://teleport.example.com",
			},
		},
	}

	// Marshal to JSON (what the REST API returns)
	jsonData, err := json.Marshal(challenge)
	require.NoError(t, err, "Failed to marshal challenge")

	t.Logf("JSON output: %s", string(jsonData))

