		t.Errorf("testEmbeddedPointerFlattening failed: %v", err)
	}

	if err := testChallengeFieldPreservation(); err != nil {
		t.Errorf("testChallengeFieldPreservation failed: %v", err)
	}

	if err := testBackwardsCompatibility(); err != nil {
		t.Errorf("testBackwardsCompatibility failed: %v", err)
